@Controller('$ROUTE_PREFIX')
export class $NAMEController {
	constructor(private readonly $NAME_LOWERService: $NAMEService) {}

	@Get()
	async findAll(@Query('$QUERY_PARAM') $QUERY_PARAM?: string): Promise<$ENTITY[]> {
		return this.$NAME_LOWERService.findAll($QUERY_PARAM);
