import { Injectable, NotFoundException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { $ENTITY } from './entities/$ENTITY_LOWER.entity';
import { Create$NAMEDto } from './dto/create-$NAME_LOWER.dto';
import { Update$NAMEDto } from './dto/update-$NAME_LOWER.dto';

@Injectable()
export class $NAMEService {
	constructor(
		@InjectRepository($ENTITY)
		private readonly $ENTITY_LOWERRepository: Repository<$ENTITY>,
	) {}

	async findAll($FILTER_PARAM?: string): Promise<$ENTITY[]> {
		const query = this.$ENTITY_LOWERRepository.createQueryBuilder('$ALIAS');

		if ($FILTER_PARAM) {
			query.where('$ALIAS.$FILTER_FIELD LIKE :$FILTER_PARAM', {
				$FILTER_PARAM: `%${$FILTER_PARAM}%`,
			});
		}

		return query.getMany();
	}

	async findOne(id: string): Promise<$ENTITY> {
		const $ENTITY_LOWER = await this.$ENTITY_LOWERRepository.findOne({
			where: { id },
		});

		if (!$ENTITY_LOWER) {
			throw new NotFoundException(`$ENTITY with ID "${id}" not found`);
		}

		return $ENTITY_LOWER;
	}

	async create(create$NAMEDto: Create$NAMEDto): Promise<$ENTITY> {
		const $ENTITY_LOWER = this.$ENTITY_LOWERRepository.create(create$NAMEDto);
		return this.$ENTITY_LOWERRepository.save($ENTITY_LOWER);
	}

	async update(id: string, update$NAMEDto: Update$NAMEDto): Promise<$ENTITY> {
		const $ENTITY_LOWER = await this.findOne(id);
		Object.assign($ENTITY_LOWER, update$NAMEDto);
		return this.$ENTITY_LOWERRepository.save($ENTITY_LOWER);
	}

	async remove(id: string): Promise<void> {
		const $ENTITY_LOWER = await this.findOne(id);
		await this.$ENTITY_LOWERRepository.remove($ENTITY_LOWER);
	}
}

