export interface Response<T> {
	data: T;
	timestamp: string;
}

@Injectable()
export class $NAMEInterceptor<T> implements NestInterceptor<T, Response<T>> {
	intercept(
		context: ExecutionContext,
		next: CallHandler<T>
	): Observable<Response<T>> {
		const now = Date.now();

		return next.handle().pipe(
			tap(() => {
				console.log(`$LOG_PREFIX: ${Date.now() - now}ms`);
			}),
			map((data) => ({
				data,
				timestamp: new Date().toISOString(),
			})),
		);
	}
}

