@Injectable()
export class $NAMERepository extends Repository<$ENTITY> {
	constructor(private readonly dataSource: DataSource) {
		super($ENTITY, dataSource.createEntityManager());
	}

	async findBy$FIELD($FIELD_NAME: $FIELD_TYPE): Promise<$ENTITY[]> {
		return this.createQueryBuilder('$ALIAS')
			.where('$ALIAS.$FIELD_NAME = :$FIELD_NAME', { $FIELD_NAME })
			.getMany();
	}

	async findWithRelations(id: string): Promise<$ENTITY | null> {
		return this.createQueryBuilder('$ALIAS')
			.leftJoinAndSelect('$ALIAS.$RELATION', '$RELATION_ALIAS')
			.where('$ALIAS.id = :id', { id })
			.getOne();
	}
}

